/* Filter Utils, By BlackStar, Vers.0.1.0 */
(()=>{const isRange=condition=>condition&&typeof condition==="object"&&("min"in condition||"max"in condition);const filterObjs=(objects,filters)=>{const length=filters.length;delete filters.length;const result=[];let count=0;for(const obj of objects){if(length&&count>=length){break}const isMatch=Object.entries(filters).every((([key,condition])=>{const val=obj[key];if(isRange(condition)){const{min:min,max:max}=condition;if(min!==undefined&&val<min)return false;if(max!==undefined&&val>max)return false;return true}else if(Array.isArray(condition)){return condition.includesAll(val)}else if(typeof condition==="number"||typeof condition==="string"){return val===condition}return true}));if(isMatch){result.push(obj);count++}}return result};setup.filterObjs=filterObjs;window.filterObjs=window.filterObjs||filterObjs})();
/* End Filter Utils */